import{_ as a,o as l,c as r,a2 as e}from"./chunks/framework.B72_uj9U.js";const b=JSON.parse('{"title":"工人保密访谈指引（服装行业专版）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/garment/worker-interview.md","filePath":"zh/industry/garment/worker-interview.md"}'),i={name:"zh/industry/garment/worker-interview.md"};function o(d,t,h,n,s,c){return l(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="工人保密访谈指引-服装行业专版" tabindex="-1">工人保密访谈指引（服装行业专版） <a class="header-anchor" href="#工人保密访谈指引-服装行业专版" aria-label="Permalink to &quot;工人保密访谈指引（服装行业专版）&quot;">​</a></h1><blockquote><p><strong>适用场景：</strong> 服装工厂现场审核，工人保密访谈环节</p><p><strong>前提条件：</strong> 访谈须在无管理层在场的私密空间进行。向工人说明：访谈内容保密，不会反馈给工厂管理层，参与完全自愿。</p></blockquote><hr><h2 id="访谈开场白-参考话术" tabindex="-1">访谈开场白（参考话术） <a class="header-anchor" href="#访谈开场白-参考话术" aria-label="Permalink to &quot;访谈开场白（参考话术）&quot;">​</a></h2><blockquote><p>&quot;您好，我们是来自 [采购公司/第三方机构] 的独立审核员。我们此行是为了了解工厂的真实工作情况。您的回答是保密的——我们不会把您的名字或具体说法告诉工厂管理层。参加访谈完全是自愿的，您可以随时停止。请放心地告诉我们实际情况。&quot;</p></blockquote><hr><h2 id="模块一-基本工作情况" tabindex="-1">模块一　基本工作情况 <a class="header-anchor" href="#模块一-基本工作情况" aria-label="Permalink to &quot;模块一　基本工作情况&quot;">​</a></h2><ol><li>您在这里做什么工种？做了多长时间了？</li><li>您是正式员工还是通过中介派来的？合同是多长时间的？</li><li>您的工作班次是怎么安排的？（几点上班、几点下班？）</li><li>您上周一共工作了多少小时？上个月呢？</li><li>最忙的时候（旺季），您通常一天工作多少小时？最多工作到几点？</li><li>加班是自愿的吗？如果您想不加班，会有什么后果？</li></ol><h2 id="模块二-工资与扣款" tabindex="-1">模块二　工资与扣款 <a class="header-anchor" href="#模块二-工资与扣款" aria-label="Permalink to &quot;模块二　工资与扣款&quot;">​</a></h2><ol start="7"><li>您的基本工资是多少？加班费怎么算的？</li><li>发工资的时候，会从您的工资里扣什么钱吗？（餐费、住宿费、工装费等）</li><li>工资单上的数字，您看得懂吗？有没有发现过错误？</li><li>您收到的工资和工资单上写的一致吗？</li><li>工资一般什么时候发？有没有出现过延迟发薪的情况？</li></ol><h2 id="模块三-自由与权利" tabindex="-1">模块三　自由与权利 <a class="header-anchor" href="#模块三-自由与权利" aria-label="Permalink to &quot;模块三　自由与权利&quot;">​</a></h2><ol start="12"><li>您在工厂外居住，还是住在厂里的宿舍？宿舍晚上几点锁门？</li><li>您来这里工作时，有没有交过押金或者中介费？</li><li>工厂有没有扣押过您的身份证或护照？</li><li>如果您不想在这里工作了，可以随时离开吗？</li></ol><h2 id="模块四-申诉与安全" tabindex="-1">模块四　申诉与安全 <a class="header-anchor" href="#模块四-申诉与安全" aria-label="Permalink to &quot;模块四　申诉与安全&quot;">​</a></h2><ol start="16"><li>工厂有没有让工人反映问题的渠道（投诉箱、热线等）？您会用吗？为什么？</li><li>工厂里有工会或者工人代表吗？他们有没有帮工人解决过实际问题？</li><li>如果发生工伤，工厂是怎么处理的？有工伤赔偿吗？</li><li>您觉得工厂里有没有什么安全隐患？</li></ol><h2 id="模块五-建筑与消防" tabindex="-1">模块五　建筑与消防 <a class="header-anchor" href="#模块五-建筑与消防" aria-label="Permalink to &quot;模块五　建筑与消防&quot;">​</a></h2><ol start="20"><li>您有参加过消防演练吗？最近一次是什么时候？</li><li>紧急出口的位置，您清楚吗？出口通道平时畅通吗？</li><li>工厂大楼有没有出现过裂缝、渗水或者结构方面的问题？</li></ol><h2 id="模块六-化学品-染整-后整理工序工人适用" tabindex="-1">模块六　化学品（染整/后整理工序工人适用） <a class="header-anchor" href="#模块六-化学品-染整-后整理工序工人适用" aria-label="Permalink to &quot;模块六　化学品（染整/后整理工序工人适用）&quot;">​</a></h2><ol start="23"><li>您工作中会接触到哪些化学品？</li><li>工厂有没有给您提供防护手套、口罩等防护用品？</li><li>有没有发生过化学品泄漏或者工人因化学品受伤的事情？</li></ol><hr><h2 id="访谈结束" tabindex="-1">访谈结束 <a class="header-anchor" href="#访谈结束" aria-label="Permalink to &quot;访谈结束&quot;">​</a></h2><blockquote><p>&quot;感谢您今天抽时间和我们交流。您说的情况对我们非常重要。请问您还有什么想补充的，或者有什么问题想问我们的吗？&quot;</p></blockquote><hr><h2 id="审核员记录表-访谈后填写" tabindex="-1">审核员记录表（访谈后填写） <a class="header-anchor" href="#审核员记录表-访谈后填写" aria-label="Permalink to &quot;审核员记录表（访谈后填写）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>记录</th></tr></thead><tbody><tr><td>访谈编号（匿名）</td><td>WI-GAR-___</td></tr><tr><td>访谈时间</td><td></td></tr><tr><td>工种/工序</td><td></td></tr><tr><td>工龄</td><td></td></tr><tr><td>主要发现（关键引语）</td><td></td></tr><tr><td>标记风险</td><td>□ 加班 □ 工资 □ 自由 □ 安全 □ 化学品 □ 其他</td></tr><tr><td>需跟进事项</td><td></td></tr><tr><td>审核员签名</td><td></td></tr></tbody></table><blockquote><p><strong>注意：</strong> 本记录须以工人无法被识别的方式保存。切勿在记录中写入工人姓名、工号或任何可识别信息。</p></blockquote>',25)])])}const q=a(i,[["render",o]]);export{b as __pageData,q as default};
